function selectionSort(a) {
  for (let i = 0; i < a.length; i++) {
    let m = i;
    for (let j = i + 1; j < a.length; j++) {
      if (a[j] < a[m]) m = j;
    }
    const t = a[i];
    a[i] = a[m];
    a[m] = t;
  }
  return a;
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(selectionSort([5, 2, 4, 6, 1]), [1, 2, 4, 5, 6])) throw new Error('basic');
if (!eq(selectionSort([]), [])) throw new Error('empty');
if (!eq(selectionSort([3, 3, 1]), [1, 3, 3])) throw new Error('dups');

solution:
function insertionSort(a) {
  for (let i = 1; i < a.length; i++) {
    const key = a[i];
    let j = i - 1;
    while (j >= 0 && a[j] > key) {
      a[j + 1] = a[j];
      j--;
    }
    a[j + 1] = key;
  }
  return a;
}

