function mergeSort(a) {
  if (a.length <= 1) return a.slice();
  const mid = Math.floor(a.length / 2);
  const L = mergeSort(a.slice(0, mid));
  const R = mergeSort(a.slice(mid));
  const res = [];
  let i = 0, j = 0;
  while (i < L.length && j < R.length) {
    if (L[i] <= R[j]) { res.push(L[i]); i++; }
    else { res.push(R[j]); j++; }
  }
  while (i < L.length) { res.push(L[i]); i++; }
  while (j < R.length) { res.push(R[j]); j++; }
  return res;
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(mergeSort([5, 2, 4, 6, 1, 3]), [1, 2, 3, 4, 5, 6])) throw new Error('basic');
if (!eq(mergeSort([]), [])) throw new Error('empty');
const orig = [3, 1, 2];
mergeSort(orig);
if (!eq(orig, [3, 1, 2])) throw new Error('must not mutate input');

