solution:
function hasDuplicate(a) {
  const b = a.slice().sort((x, y) => x - y);
  for (let i = 1; i < b.length; i++) {
    if (b[i] === b[i - 1]) return true;
  }
  return false;
}

tests:
if (hasDuplicate([1, 2, 3, 1]) !== true) throw new Error('has dup');
if (hasDuplicate([1, 2, 3]) !== false) throw new Error('no dup');
if (hasDuplicate([]) !== false) throw new Error('empty');
const o = [3, 1, 2, 1];
hasDuplicate(o);
if (JSON.stringify(o) !== JSON.stringify([3, 1, 2, 1])) throw new Error('must not mutate input');

