  // your code here
}

solution:
function twoSumSorted(a, target) {
  const b = a.slice().sort((x, y) => x - y);
  let i = 0, j = b.length - 1;
  while (i < j) {
    const s = b[i] + b[j];
    if (s === target) return [b[i], b[j]];
    else if (s < target) i++;
    else j--;
  }
  return null;
}

tests:
const eq = (x, y) => JSON.stringify(x) === JSON.stringify(y);
if (!eq(twoSumSorted([8, 1, 3, 5], 8), [3, 5])) throw new Error('unsorted input');
if (!eq(twoSumSorted([2, 7, 11, 15], 9), [2, 7])) throw new Error('ends');
if (twoSumSorted([1, 2, 4], 8) !== null) throw new Error('no pair -> null');

